-- ═══════════════════════════════════════════════════════════════════════════
-- ManuMan — SEED DATI TEST v2 (COMPLETO)
-- Esegui nel Supabase SQL Editor:
-- https://supabase.com/dashboard/project/nnsylkjahuhttwajuxls/sql
--
-- IDEMPOTENTE: salta silenziosamente se i dati esistono già
-- Dataset: 4 clienti, 6 asset, 4 operatori, 3 piani PM, 12 manutenzioni
--          (tutti gli stati), 6 ticket (tutti gli stati), 3 OdL, 5 ricambi,
--          2 ordini acquisto, 3 fornitori, 2 gruppi, 4 scadenze, 2 template
-- ═══════════════════════════════════════════════════════════════════════════

DO $$ DECLARE tid uuid; -- clienti c1 bigint; c2 bigint; c3 bigint; c4 bigint; -- assets a1 bigint; a2 bigint; a3 bigint; a4 bigint; a5 bigint; a6 bigint; -- operatori op1 bigint; op2 bigint; op3 bigint; op4 bigint; -- piani p1 bigint; p2 bigint; p3 bigint; -- piano_voci pv1 bigint; pv2 bigint; pv3 bigint; pv4 bigint; -- piano_checklist pc1 bigint; pc2 bigint; pc3 bigint; -- assegnazioni ass1 bigint; ass2 bigint; ass3 bigint; ass4 bigint; -- manutenzioni m1 bigint; m2 bigint; m3 bigint; m4 bigint; m5 bigint; m6 bigint; m7 bigint; m8 bigint; m9 bigint; m10 bigint; m11 bigint; m12 bigint; -- tickets t1 bigint; t2 bigint; t3 bigint; t4 bigint; t5 bigint; t6 bigint; -- odl odl1 bigint; odl2 bigint; odl3 bigint; -- ricambi r1 bigint; r2 bigint; r3 bigint; r4 bigint; r5 bigint; -- ordini acquisto oa1 bigint; oa2 bigint; -- fornitori f1 bigint; f2 bigint; f3 bigint; -- sla sla1 bigint; sla2 bigint; -- gruppi grp1 bigint; grp2 bigint; -- template tpl1 bigint; tpl2 bigint; BEGIN SELECT id INTO tid FROM tenants ORDER BY created_at LIMIT 1; IF tid IS NULL THEN RAISE NOTICE 'Nessun tenant — seed saltato'; RETURN; END IF; IF EXISTS (SELECT 1 FROM clienti WHERE tenant_id=tid AND codice='CLI001') THEN RAISE NOTICE 'Seed v1 già presente — eseguo solo il v2 extra'; END IF; -- ═══════════════════════════════════════════════════════════════════ -- SLA PROFILI (2 profili) -- ═══════════════════════════════════════════════════════════════════ INSERT INTO sla_profili (nome, colore, is_default, tenant_id) VALUES ('Standard', '#0EA5E9', true, tid) ON CONFLICT DO NOTHING RETURNING id INTO sla1; IF sla1 IS NULL THEN SELECT id INTO sla1 FROM sla_profili WHERE tenant_id=tid AND nome='Standard'; END IF; INSERT INTO sla_profili (nome, colore, is_default, tenant_id) VALUES ('Premium 24/7', '#10B981', false, tid) ON CONFLICT DO NOTHING RETURNING id INTO sla2; IF sla2 IS NULL THEN SELECT id INTO sla2 FROM sla_profili WHERE tenant_id=tid AND nome='Premium 24/7'; END IF; INSERT INTO sla_profilo_config (profilo_id, priorita, ore_risposta, ore_risoluzione, ordine, tenant_id) VALUES (sla1,'urgente',1,4,1,tid),(sla1,'alta',4,24,2,tid),(sla1,'media',8,48,3,tid),(sla1,'bassa',24,120,4,tid), (sla2,'urgente',0,2,1,tid),(sla2,'alta',2,8,2,tid),(sla2,'media',4,24,3,tid),(sla2,'bassa',8,48,4,tid) ON CONFLICT DO NOTHING; -- ═══════════════════════════════════════════════════════════════════ -- CLIENTI (4) -- ═══════════════════════════════════════════════════════════════════ INSERT INTO clienti (rs, codice, piva, contatto, tel, email, ind, settore, note, sla_profilo_id, tenant_id) VALUES ('Acciaierie Nordest SpA','CLI001','12345678901','Ing. Marco Ferretti','049 1234567','ferretti@acciaierie-nordest.it','Via Industria 12, Padova','metallurgia','Cliente storico dal 2018',sla1,tid), ('Plastiche Venete Srl','CLI002','98765432101','Dott.ssa Laura Boni','045 7654321','boni@plastichevenete.it','Via Roma 45, Verona','plastica','Revisione impianti trimestrale',sla1,tid), ('Cartiera Alpi SpA','CLI003','11122233344','Geom. Franco Rizzi','0423 891234','rizzi@cartieraalpi.it','Via Montagna 3, Belluno','cartaria','',sla2,tid), ('Farmaceutica Sud Srl','CLI004','55544433321','Dr. Antonio Mele','081 9988776','mele@farmasud.it','Via Napoli 8, Salerno','farmaceutica','Contratto premium 24/7',sla2,tid) ON CONFLICT DO NOTHING; SELECT id INTO c1 FROM clienti WHERE tenant_id=tid AND codice='CLI001'; SELECT id INTO c2 FROM clienti WHERE tenant_id=tid AND codice='CLI002'; SELECT id INTO c3 FROM clienti WHERE tenant_id=tid AND codice='CLI003'; SELECT id INTO c4 FROM clienti WHERE tenant_id=tid AND codice='CLI004'; -- ═══════════════════════════════════════════════════════════════════ -- OPERATORI (4: 2 fornitori esterni, 1 interno, 1 fornitore specializzato) -- ═══════════════════════════════════════════════════════════════════ INSERT INTO operatori (nome, spec, col, tipo, email, tariffa_ora, tenant_id) VALUES ('Elettromeccanica Rossi','Impianti elettrici, PLC e quadri','#3B82F6','fornitore','info@elettromeccanica-rossi.it',65.00,tid), ('Idraulica Bianchi & Figli','Sistemi idraulici e pneumatici','#059669','fornitore','bianchi@idraulica-bf.it',58.00,tid), ('Mario Tecnico','Manutenzione meccanica generica','#F59E0B','interno','mario@interno.it',null,tid), ('TechnoService Srl','Strumentazione e automazione industriale','#8B5CF6','fornitore','ops@technoservice.it',85.00,tid) ON CONFLICT DO NOTHING; SELECT id INTO op1 FROM operatori WHERE tenant_id=tid AND nome='Elettromeccanica Rossi'; SELECT id INTO op2 FROM operatori WHERE tenant_id=tid AND nome='Idraulica Bianchi & Figli'; SELECT id INTO op3 FROM operatori WHERE tenant_id=tid AND nome='Mario Tecnico'; SELECT id INTO op4 FROM operatori WHERE tenant_id=tid AND nome='TechnoService Srl'; -- Assegna siti (operatori→clienti) INSERT INTO operatore_siti (operatore_id, cliente_id, tenant_id) VALUES (op1,c1,tid),(op1,c4,tid),(op2,c1,tid),(op2,c2,tid),(op3,c1,tid),(op3,c2,tid),(op3,c3,tid),(op4,c4,tid) ON CONFLICT DO NOTHING; -- ═══════════════════════════════════════════════════════════════════ -- ASSETS (6 impianti reali con dati tecnici) -- ═══════════════════════════════════════════════════════════════════ INSERT INTO assets (nome, tipo, cliente_id, ubicazione, matricola, marca, modello, data_inst, stato, ore_utilizzo, soglia_ore, costo_acquisto, garanzia_al, vita_utile_anni, note, tenant_id) VALUES ('Pressa Idraulica 500T','pressa',c1,'Reparto A - Linea 1','PH-500-2019-001','Schuler','MSP 500','2019-03-15','attivo',12450,15000,285000.00,'2024-03-15',20,'Revisione annuale certificata',tid), ('Compressore Atlas 75kW','compressore',c1,'Centrale Aria','CA-75-2020-003','Atlas Copco','GA75VSD','2020-06-01','attivo',8320,10000,42000.00,'2025-06-01',15,'Filtro prossimo a scadenza',tid), ('Estrusore Linea 2','estrusore',c2,'Linea Produzione 2','EX-2-2018-007','Battenfeld','HM 1800/525','2018-09-10','manutenzione',22100,null,195000.00,'2023-09-10',18,'In revisione pompa olio',tid), ('Raffinatore Carta RK-3','raffinatore',c3,'Sala Macchine','RK-3-2021-001','Valmet','OptiFiner','2021-01-20','attivo',5600,8000,320000.00,'2026-01-20',25,'',tid), ('Generatore Emergenza GE-1','generatore',c1,'Locale Tecnico','GE-2022-001','Kohler','KD2500','2022-05-01','attivo',890,2000,38000.00,'2027-05-01',20,'Test mensile obbligatorio',tid), ('Linea Confezionamento LC-7','linea',c4,'Reparto Produzione','LC-7-2023-001','IMA','Solid 100','2023-02-10','attivo',3200,5000,520000.00,'2028-02-10',20,'Classe A farmaceutica',tid) ON CONFLICT DO NOTHING; SELECT id INTO a1 FROM assets WHERE tenant_id=tid AND matricola='PH-500-2019-001'; SELECT id INTO a2 FROM assets WHERE tenant_id=tid AND matricola='CA-75-2020-003'; SELECT id INTO a3 FROM assets WHERE tenant_id=tid AND matricola='EX-2-2018-007'; SELECT id INTO a4 FROM assets WHERE tenant_id=tid AND matricola='RK-3-2021-001'; SELECT id INTO a5 FROM assets WHERE tenant_id=tid AND matricola='GE-2022-001'; SELECT id INTO a6 FROM assets WHERE tenant_id=tid AND matricola='LC-7-2023-001'; -- ═══════════════════════════════════════════════════════════════════ -- RICAMBI (5 con stock e soglie) -- ═══════════════════════════════════════════════════════════════════ INSERT INTO ricambi (nome, codice, categoria, prezzo, quantita_stock, soglia_minima, fornitore, note, tenant_id) VALUES ('Filtro olio 75 micron','FO-075-001','filtri',28.50,12,4,'Filtri Italia Srl','Sostituire ogni 500h',tid), ('Guarnizione pompa idraulica','GP-HYD-023','guarnizioni',15.80,8,3,'Idrotech SpA','Per Schuler MSP 500',tid), ('Cinghia trapezoidale B78','CT-B78-001','trasmissione',22.00,6,2,'SKF Italia','',tid), ('Cuscinetto SKF 6205-2Z','CS-6205-001','cuscinetti',18.90,15,5,'SKF Italia','Cuscinetto di ricambio standard',tid), ('Valvola solenoide 24V','VS-24V-003','pneumatica',145.00,3,2,'Festo Italia','Per circuiti pneumatici Atlas',tid) ON CONFLICT DO NOTHING; SELECT id INTO r1 FROM ricambi WHERE tenant_id=tid AND codice='FO-075-001'; SELECT id INTO r2 FROM ricambi WHERE tenant_id=tid AND codice='GP-HYD-023'; SELECT id INTO r3 FROM ricambi WHERE tenant_id=tid AND codice='CT-B78-001'; SELECT id INTO r4 FROM ricambi WHERE tenant_id=tid AND codice='CS-6205-001'; SELECT id INTO r5 FROM ricambi WHERE tenant_id=tid AND codice='VS-24V-003'; -- ═══════════════════════════════════════════════════════════════════ -- PIANI DI MANUTENZIONE (3) -- ═══════════════════════════════════════════════════════════════════ INSERT INTO piani (nome, descrizione, tipo, frequenza, durata, priorita, attivo, aggregazione_odl, tenant_id) VALUES ('PM Mensile Impianti Idraulici','Controllo livelli olio, pressioni e tenute','ordinaria','mensile',90,'media',true,'per_visita',tid), ('PM Trimestrale Elettrico','Verifica quadri, morsetti e isolamenti','ordinaria','trimestrale',120,'alta',true,'per_visita',tid), ('PM Semestrale Farmaceutico','Qualifica IQ/OQ impianti classe A','ordinaria','semestrale',240,'urgente',true,'per_visita',tid) ON CONFLICT DO NOTHING; SELECT id INTO p1 FROM piani WHERE tenant_id=tid AND nome='PM Mensile Impianti Idraulici'; SELECT id INTO p2 FROM piani WHERE tenant_id=tid AND nome='PM Trimestrale Elettrico'; SELECT id INTO p3 FROM piani WHERE tenant_id=tid AND nome='PM Semestrale Farmaceutico'; -- Piano voci INSERT INTO piano_voci (piano_id, titolo, frequenza, durata, tipo, priorita, ordine, attivo, tenant_id) VALUES (p1,'Controllo livello olio idraulico','mensile',30,'ordinaria','media',1,true,tid), (p1,'Verifica pressione circuito primario','mensile',20,'ordinaria','media',2,true,tid), (p1,'Sostituzione filtro olio','trimestrale',45,'ordinaria','alta',3,true,tid), (p2,'Termografia quadri elettrici','trimestrale',60,'ordinaria','alta',1,true,tid), (p2,'Serraggio morsetti MT/BT','semestrale',45,'ordinaria','alta',2,true,tid), (p3,'Qualifica IQ strumentazione','semestrale',120,'ordinaria','urgente',1,true,tid), (p3,'Calibrazione sensori temperatura','semestrale',90,'ordinaria','urgente',2,true,tid) ON CONFLICT DO NOTHING; -- Piano checklist INSERT INTO piano_checklist (piano_id, testo, obbligatorio, ordine, tenant_id) VALUES (p1,'Verificare livello olio > 80% serbatoio',true,1,tid), (p1,'Controllare assenza perdite su raccordi',true,2,tid), (p1,'Misurare temperatura olio (max 60°C)',true,3,tid), (p2,'Verifica continuità di terra',true,1,tid), (p2,'Controllo temperatura quadri con termocamera',true,2,tid), (p3,'Verifica certificati calibrazione strumenti',true,1,tid), (p3,'Check documentazione GMP',true,2,tid), (p3,'Test funzionalità safety interlocks',true,3,tid) ON CONFLICT DO NOTHING; -- Piano assegnazioni (piano→asset) INSERT INTO piano_assegnazioni (piano_id, asset_id, cliente_id, operatore_id, data_inizio, attivo, scope, tenant_id) VALUES (p1,a1,c1,op2,CURRENT_DATE-120,true,'asset',tid), (p1,a2,c1,op2,CURRENT_DATE-90,true,'asset',tid), (p1,a3,c2,op2,CURRENT_DATE-60,true,'asset',tid), (p2,a1,c1,op1,CURRENT_DATE-180,true,'asset',tid), (p2,a5,c1,op1,CURRENT_DATE-180,true,'asset',tid), (p3,a6,c4,op4,CURRENT_DATE-30,true,'asset',tid) ON CONFLICT DO NOTHING; SELECT id INTO ass1 FROM piano_assegnazioni WHERE piano_id=p1 AND asset_id=a1; SELECT id INTO ass2 FROM piano_assegnazioni WHERE piano_id=p1 AND asset_id=a2; SELECT id INTO ass3 FROM piano_assegnazioni WHERE piano_id=p2 AND asset_id=a1; SELECT id INTO ass4 FROM piano_assegnazioni WHERE piano_id=p3 AND asset_id=a6; -- ═══════════════════════════════════════════════════════════════════ -- MANUTENZIONI (12 in tutti gli stati) -- ═══════════════════════════════════════════════════════════════════ INSERT INTO manutenzioni (titolo, tipo, stato, priorita, operatore_id, cliente_id, asset_id, piano_id, data, durata, note, fermo_impianto, assegnazione_id, tenant_id) VALUES -- Completate (storico) ('Controllo olio mensile — Pressa 500T','ordinaria','completata','media',op2,c1,a1,p1,CURRENT_DATE-65,90,'Olio al 82%, integrato. Nessuna anomalia.',false,ass1,tid), ('Verifica pressione circuito — Pressa 500T','ordinaria','completata','media',op2,c1,a1,p1,CURRENT_DATE-65,20,'Pressione regolata 185 bar.',false,ass1,tid), ('Controllo olio mensile — Compressore Atlas','ordinaria','completata','media',op2,c1,a2,p1,CURRENT_DATE-65,60,'Livello ok. Filtro segnalato.',false,ass2,tid), ('Termografia quadri elettrici — Pressa 500T','ordinaria','completata','alta',op1,c1,a1,p2,CURRENT_DATE-90,75,'Nessuna anomalia termica. Documentazione archiviata.',false,ass3,tid), -- Completate (mese scorso) ('Controllo olio mensile — Pressa 500T','ordinaria','completata','media',op2,c1,a1,p1,CURRENT_DATE-32,90,'Livello olio al 75%, rabboccato. Verifica tenute ok.',false,ass1,tid), ('Controllo olio mensile — Compressore Atlas','ordinaria','completata','media',op2,c1,a2,p1,CURRENT_DATE-32,60,'Sostituzione filtro olio effettuata.',false,ass2,tid), -- In corso (guasto attivo) ('Sostituzione guarnizione pompa olio — Estrusore L2','correttiva','inCorso','alta',op2,c2,a3,null,CURRENT_DATE-3,120,'Perdita olio pompa principale. In attesa ricambio GP-HYD-023.',true,null,tid), -- Pianificate (prossime settimane) ('Controllo olio mensile — Pressa 500T','ordinaria','pianificata','media',op2,c1,a1,p1,CURRENT_DATE+8,90,'',false,ass1,tid), ('Controllo olio mensile — Compressore Atlas','ordinaria','pianificata','media',op2,c1,a2,p1,CURRENT_DATE+8,60,'',false,ass2,tid), ('Verifica pressione — Estrusore L2','ordinaria','pianificata','media',op2,c2,a3,p1,CURRENT_DATE+15,45,'Da eseguire dopo riparazione pompa.',false,ass3,tid), -- Scaduta (non eseguita in tempo) ('Serraggio morsetti MT/BT — Generatore','ordinaria','scaduta','alta',op1,c1,a5,p2,CURRENT_DATE-5,45,'',false,null,tid), -- Farmaceutico (pianificata) ('Qualifica IQ — Linea Confezionamento LC-7','ordinaria','pianificata','urgente',op4,c4,a6,p3,CURRENT_DATE+30,240,'Prima qualifica dopo installazione.',false,ass4,tid) ON CONFLICT DO NOTHING; SELECT id INTO m1 FROM manutenzioni WHERE tenant_id=tid AND titolo='Controllo olio mensile — Pressa 500T' AND data=CURRENT_DATE-65; SELECT id INTO m2 FROM manutenzioni WHERE tenant_id=tid AND titolo='Verifica pressione circuito — Pressa 500T'; SELECT id INTO m3 FROM manutenzioni WHERE tenant_id=tid AND titolo='Controllo olio mensile — Compressore Atlas' AND data=CURRENT_DATE-65; SELECT id INTO m4 FROM manutenzioni WHERE tenant_id=tid AND titolo='Termografia quadri elettrici — Pressa 500T'; SELECT id INTO m5 FROM manutenzioni WHERE tenant_id=tid AND titolo='Controllo olio mensile — Pressa 500T' AND data=CURRENT_DATE-32; SELECT id INTO m6 FROM manutenzioni WHERE tenant_id=tid AND titolo='Controllo olio mensile — Compressore Atlas' AND data=CURRENT_DATE-32; SELECT id INTO m7 FROM manutenzioni WHERE tenant_id=tid AND titolo='Sostituzione guarnizione pompa olio — Estrusore L2'; SELECT id INTO m8 FROM manutenzioni WHERE tenant_id=tid AND titolo='Controllo olio mensile — Pressa 500T' AND data=CURRENT_DATE+8; SELECT id INTO m9 FROM manutenzioni WHERE tenant_id=tid AND titolo='Controllo olio mensile — Compressore Atlas' AND data=CURRENT_DATE+8; SELECT id INTO m10 FROM manutenzioni WHERE tenant_id=tid AND titolo='Verifica pressione — Estrusore L2'; SELECT id INTO m11 FROM manutenzioni WHERE tenant_id=tid AND titolo='Serraggio morsetti MT/BT — Generatore'; SELECT id INTO m12 FROM manutenzioni WHERE tenant_id=tid AND titolo='Qualifica IQ — Linea Confezionamento LC-7'; -- Chiudi le manutenzioni completate UPDATE manutenzioni SET stato='completata', chiuso_at=NOW()-interval '65 days', ore_effettive=1.5, note_chiusura='Completato regolarmente. Nessuna anomalia.' WHERE id=m1; UPDATE manutenzioni SET stato='completata', chiuso_at=NOW()-interval '65 days', ore_effettive=0.4, note_chiusura='Pressione portata a 185 bar nominali.' WHERE id=m2; UPDATE manutenzioni SET stato='completata', chiuso_at=NOW()-interval '65 days', ore_effettive=1.0, note_chiusura='Filtro segnalato per sostituzione a 3 mesi.' WHERE id=m3; UPDATE manutenzioni SET stato='completata', chiuso_at=NOW()-interval '90 days', ore_effettive=1.3, note_chiusura='Termografia ok, report allegato.' WHERE id=m4; UPDATE manutenzioni SET stato='completata', chiuso_at=NOW()-interval '32 days', ore_effettive=1.5, note_chiusura='Rabboccato olio, tutto regolare.' WHERE id=m5; UPDATE manutenzioni SET stato='completata', chiuso_at=NOW()-interval '32 days', ore_effettive=1.0, note_chiusura='Filtro sostituito con FO-075-001.' WHERE id=m6; -- Ricambi usati negli interventi INSERT INTO intervento_ricambi (manutenzione_id, ricambio_id, quantita, note, tenant_id) VALUES (m5,r1,1,'Rabbocco olio con filtro nuovo',tid), (m6,r1,1,'Sostituzione filtro programmata',tid), (m7,r2,2,'Guarnizioni pompa principale e secondaria',tid) ON CONFLICT DO NOTHING; -- Commenti sulle attività INSERT INTO attivita_commenti (manutenzione_id, autore_nome, testo, tipo, tenant_id) VALUES (m7,'Mario Tecnico','Perdita confermata lato sinistro pompa. Olio sul pavimento circa 0.5L/h.','commento',tid), (m7,'Idraulica Bianchi & Figli','Ordinato ricambio GP-HYD-023 × 2. Consegna stimata domani mattina.','commento',tid), (m7,'Mario Tecnico','Macchina isolata e messa in sicurezza. Cliente avvisato.','commento',tid), (m11,'Mario Tecnico','Intervento scaduto — operatore non disponibile settimana scorsa. Da ripianificare urgente.','commento',tid) ON CONFLICT DO NOTHING; -- ═══════════════════════════════════════════════════════════════════ -- TICKETS (6 in tutti gli stati del flusso) -- ═══════════════════════════════════════════════════════════════════ INSERT INTO tickets (numero, titolo, tipo, priorita, stato, cliente_id, asset_id, operatore_id, descrizione, causa_guasto, fermo_impianto, segnalatore_nome, segnalatore_email, tenant_id) VALUES ('TKT-2025-001','Perdita olio pompa pressa idraulica','correttiva','alta','in_lavorazione',c1,a1,op2, 'Macchia olio sotto la pressa 500T. Perdita dalla pompa principale stimata 0.3 L/h.','Usura componente',true,'Ing. Ferretti','ferretti@acciaierie-nordest.it',tid), ('TKT-2025-002','Rumore anomalo compressore Atlas','correttiva','media','aperto',c1,a2,null, 'Rumore metallico intermittente dal compressore durante la fase di carica. Iniziato 3 giorni fa.','',false,'Ing. Ferretti','ferretti@acciaierie-nordest.it',tid), ('TKT-2025-003','Revisione completa estrusore linea 2','preventiva','media','in_attesa',c2,a3,null, 'Richiedere revisione completa prima della ripresa produzione autunnale.','',false,'Dott.ssa Boni','boni@plastichevenete.it',tid), ('TKT-2025-004','Taratura strumenti linea confezionamento','normativa','urgente','aperto',c4,a6,op4, 'Scadenza taratura annuale GMP entro 15 giorni. Richiesta urgente.','',false,'Dr. Mele','mele@farmasud.it',tid), ('TKT-2024-089','Sostituzione cinghie trasmissione raffinatore','correttiva','bassa','chiuso',c3,a4,op3, 'Cinghie consumate con gioco eccessivo.','Usura normale',false,'Geom. Rizzi','rizzi@cartieraalpi.it',tid), ('TKT-2025-005','Verifica impianto elettrico quadro A','preventiva','media','in_attesa',c1,null,null, 'Verifica periodica annuale impianto elettrico stabilimento — quadro linea A.','',false,'Ing. Ferretti','ferretti@acciaierie-nordest.it',tid) ON CONFLICT DO NOTHING; SELECT id INTO t1 FROM tickets WHERE tenant_id=tid AND numero='TKT-2025-001'; SELECT id INTO t2 FROM tickets WHERE tenant_id=tid AND numero='TKT-2025-002'; SELECT id INTO t3 FROM tickets WHERE tenant_id=tid AND numero='TKT-2025-003'; SELECT id INTO t4 FROM tickets WHERE tenant_id=tid AND numero='TKT-2025-004'; SELECT id INTO t5 FROM tickets WHERE tenant_id=tid AND numero='TKT-2024-089'; SELECT id INTO t6 FROM tickets WHERE tenant_id=tid AND numero='TKT-2025-005'; -- Chiudi TKT-2024-089 UPDATE tickets SET stato='chiuso', chiuso_at=NOW()-interval '40 days' WHERE id=t5; -- Commenti ticket INSERT INTO ticket_commenti (ticket_id, testo, autore_nome, tipo, tenant_id) VALUES (t1,'Ticket ricevuto. Tecnico idraulico contattato.','Sistema','log',tid), (t1,'In attesa ricambio GP-HYD-023. Macchina ferma in sicurezza.','Idraulica Bianchi','commento',tid), (t1,'Ricambio arrivato. Intervento in corso.','Idraulica Bianchi','commento',tid), (t2,'Aperto per verifica.